{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラは2026-05-13付で正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時開始の1時間枠で開催し、各部署から少なくとも1名が参加する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "第1フェーズのデータ移行はマスタ系のみを対象とし、トランザクション履歴は旧システムを参照用に残して対応する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "開発ベンダー候補からハギワラ技研を外す。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D5",
      "content": "開発ベンダー候補からツヅキシステムを予算超過のため見送る。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D6",
      "content": "共通基盤の認証・マスタ配信はサクラ商事との共同利用案で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "移行テストと負荷テストはシステムテストとは別立てで計画・実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "初回リリースのユーザー権限設計は既存のロール定義を流用し、新規のロール再設計は稼働後の運用改善に回す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "障害発生時の一次受け窓口はQAチームが担当し、未知のものだけ情報システム部へエスカレーションする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "本番移行は拠点をグループ分けして順次切り替える段階移行方式を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D11",
      "content": "本番リリース目標日は2026-10-15とする。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "現場ヒアリングの対象部署リストを作成して提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A2",
      "task": "検証環境のサーバ調達依頼を提出する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "API仕様書のドラフトを作成する。",
